file.content:
locals {
  common_tags = {
    Environment = var.environment
    Stack       = "iam"
  }
}

# -----------------------------------------------------------------------------
# Remote State References
# -----------------------------------------------------------------------------

data "terraform_remote_state" "storage" {
  backend = "s3"
  config = {
    bucket = var.state_bucket
    key    = "${var.aws_region}/stacks/storage/terraform.tfstate"
    region = var.state_bucket_region
  }
}

# -----------------------------------------------------------------------------
# GPU Instance Role
# -----------------------------------------------------------------------------

resource "aws_iam_role" "gpu_instance" {
  name = "${var.project_name}-${var.environment}-gpu-instance"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })

  tags = local.common_tags
}

resource "aws_iam_instance_profile" "gpu_instance" {
  name = "${var.project_name}-${var.environment}-gpu-instance"
  role = aws_iam_role.gpu_instance.name

  tags = local.common_tags
}

# SSM Session Manager access
resource "aws_iam_role_policy_attachment" "ssm" {
  role       = aws_iam_role.gpu_instance.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSSMManagedInstanceCore"
}

# CloudWatch monitoring
resource "aws_iam_role_policy_attachment" "cloudwatch" {
  role       = aws_iam_role.gpu_instance.name
  policy_arn = "arn:aws:iam::aws:policy/CloudWatchAgentServerPolicy"
}

# -----------------------------------------------------------------------------
# S3 Access Policy (for datasets and model artifacts)
# -----------------------------------------------------------------------------

resource "aws_iam_policy" "s3_data_access" {
  name        = "${var.project_name}-${var.environment}-s3-data-access"
  description = "Access to S3 artifact bucket for ML data, adapters, and checkpoints"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket",
          "s3:DeleteObject"
        ]
        Resource = [
          data.terraform_remote_state.storage.outputs.artifact_bucket_arn,
          "${data.terraform_remote_state.storage.outputs.artifact_bucket_arn}/*"
        ]
      }
    ]
  })

  tags = local.common_tags
}

resource "aws_iam_role_policy_attachment" "s3_data_access" {
  role       = aws_iam_role.gpu_instance.name
  policy_arn = aws_iam_policy.s3_data_access.arn
}

# -----------------------------------------------------------------------------
# ECR Access Policy
# -----------------------------------------------------------------------------

resource "aws_iam_policy" "ecr_access" {
  name        = "${var.project_name}-${var.environment}-ecr-access"
  description = "Pull and push access to ECR repositories"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = ["ecr:GetAuthorizationToken"]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "ecr:GetDownloadUrlForLayer",
          "ecr:BatchGetImage",
          "ecr:BatchCheckLayerAvailability",
          "ecr:PutImage",
          "ecr:InitiateLayerUpload",
          "ecr:UploadLayerPart",
          "ecr:CompleteLayerUpload"
        ]
        Resource = "arn:aws:ecr:${var.aws_region}:*:repository/${var.project_name}/*"
      }
    ]
  })

  tags = local.common_tags
}

resource "aws_iam_role_policy_attachment" "ecr_access" {
  role       = aws_iam_role.gpu_instance.name
  policy_arn = aws_iam_policy.ecr_access.arn
}

# -----------------------------------------------------------------------------
# Secrets Manager Read Policy
# -----------------------------------------------------------------------------

resource "aws_iam_policy" "secrets_read" {
  name        = "${var.project_name}-${var.environment}-secrets-read"
  description = "Read access to application secrets under project prefix"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "secretsmanager:GetSecretValue",
          "secretsmanager:DescribeSecret"
        ]
        Resource = "arn:aws:secretsmanager:*:*:secret:${var.project_name}/${var.environment}/*"
      }
    ]
  })

  tags = local.common_tags
}

resource "aws_iam_role_policy_attachment" "secrets_read" {
  role       = aws_iam_role.gpu_instance.name
  policy_arn = aws_iam_policy.secrets_read.arn
}

# -----------------------------------------------------------------------------
# Application Secret Placeholders
# -----------------------------------------------------------------------------

resource "aws_secretsmanager_secret" "app" {
  for_each = var.application_secrets

  name                    = "${var.project_name}/${var.environment}/${each.key}"
  description             = "Placeholder for ${each.key} -- fill in manually after deployment"
  recovery_window_in_days = 0

  tags = merge(local.common_tags, {
    Name  = "${var.project_name}-${var.environment}-${each.key}"
    Stack = "iam"
  })
}

resource "aws_secretsmanager_secret_version" "app" {
  for_each = var.application_secrets

  secret_id     = aws_secretsmanager_secret.app[each.key].id
  secret_string = each.value
}
